(()=>{"use strict";self.addEventListener("push",i=>{if(i.data)try{let t=i.data.json(),n=t.title||"Economizei - Nova Oferta!",o=t.body||"Temos uma nova oferta para voc\xea!",e=t.icon||"/icons/icon-192x192.png",a=t.badge||"/icons/icon-72x72.png",l=t.url||"/";i.waitUntil(self.registration.showNotification(n,{body:o,icon:e,badge:a,data:{url:l},vibrate:[200,100,200]}))}catch(i){console.error("Error parsing push payload:",i)}}),self.addEventListener("notificationclick",i=>{i.notification.close();let t=i.notification.data?.url||"/";i.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(i=>{for(let n of i)if(n.url===t&&"focus"in n)return n.focus();if(self.clients.openWindow)return self.clients.openWindow(t)}))})})();